351	/**
352	 * Bucket triangles by their normal direction in a 2D grid (nx, nz).
353	 * Triangles whose horizontal-normal lands in the same cell point in the
354	 * same direction → same roof pitch. Equivalent to a DBSCAN result but in
355	 * O(n) instead of O(n²) — required for photogrammetric meshes with 10k+ tris.
356	 */
357	function clusterRoofFaces(triangles: Triangle[]): number[][] {
358	  const GRID_RES = VARIANT_GRID_RES;
359	  const buckets = new Map<number, number[]>();
360	  for (let i = 0; i < triangles.length; i++) {
361	    const n = triangles[i].normal;
362	    const cx = Math.min(GRID_RES - 1, Math.max(0, Math.floor(((n[0] + 1) / 2) * GRID_RES)));
363	    const cz = Math.min(GRID_RES - 1, Math.max(0, Math.floor(((n[2] + 1) / 2) * GRID_RES)));
364	    const key = cx * GRID_RES + cz;
365	    let arr = buckets.get(key);
366	    if (!arr) {
367	      arr = [];
368	      buckets.set(key, arr);
369	    }
370	    arr.push(i);
371	  }
372	  return [...buckets.values()];
373	}
374	
375	function meanNormal(tris: Triangle[]): [number, number, number] {
376	  let nx = 0;
377	  let ny = 0;
378	  let nz = 0;
379	  let totalArea = 0;
380	  for (const t of tris) {
381	    nx += t.normal[0] * t.area;
382	    ny += t.normal[1] * t.area;
383	    nz += t.normal[2] * t.area;
384	    totalArea += t.area;
385	  }
386	  if (totalArea === 0) return [0, 1, 0];
387	  const len = Math.hypot(nx, ny, nz) || 1;
388	  return [nx / len, ny / len, nz / len];
389	}
390	
391	function azimuthFromNormal(n: [number, number, number]): number {
392	  // Azimuth: 0° = North, clockwise. North = +Z, East = +X.
393	  const deg = (Math.atan2(n[0], n[2]) * 180) / Math.PI;
394	  return (deg + 360) % 360;
395	}
396	
397	function tiltFromNormal(n: [number, number, number]): number {
398	  const up = Math.max(-1, Math.min(1, n[1]));
399	  return (Math.acos(up) * 180) / Math.PI;
400	}
401	
402	function convexHullXZ(points: [number, number, number][]): [number, number, number][] {
403	  // Andrew's monotone chain in the XZ plane — preserves each vertex's original
404	  // Y so a tilted roof face keeps its 3D shape (place-panels.ts needs the real
405	  // Y to build a non-degenerate face frame).
406	  if (points.length < 3) return points;
407	  const sorted = [...points].sort((a, b) => (a[0] === b[0] ? a[2] - b[2] : a[0] - b[0]));
408	
409	  const cross = (o: number[], a: number[], b: number[]) =>
410	    (a[0] - o[0]) * (b[2] - o[2]) - (a[2] - o[2]) * (b[0] - o[0]);
411	
412	  const lower: [number, number, number][] = [];
413	  for (const p of sorted) {
414	    while (lower.length >= 2 && cross(lower[lower.length - 2], lower[lower.length - 1], p) <= 0) lower.pop();
415	    lower.push(p);
416	  }
417	  const upper: [number, number, number][] = [];
418	  for (let i = sorted.length - 1; i >= 0; i--) {
419	    const p = sorted[i];
420	    while (upper.length >= 2 && cross(upper[upper.length - 2], upper[upper.length - 1], p) <= 0) upper.pop();
421	    upper.push(p);
422	  }
423	  return [...lower.slice(0, -1), ...upper.slice(0, -1)];
424	}
425	
426	function computeYield(azimuth: number, tilt: number): number {
427	  const azDelta = Math.min(Math.abs(azimuth - OPTIMAL_AZIMUTH_DEG), 360 - Math.abs(azimuth - OPTIMAL_AZIMUTH_DEG));
428	  const tiltDelta = Math.abs(tilt - OPTIMAL_TILT_DEG);
429	  const azFactor = Math.cos((azDelta * Math.PI) / 180);
430	  const tiltFactor = Math.cos((tiltDelta * Math.PI) / 180);
431	  const factor = Math.max(0.45, 0.6 + 0.2 * azFactor + 0.2 * tiltFactor);
432	  return Math.round(BASELINE_YIELD_KWH_PER_SQM * factor);
433	}
434	
435	// ─── Face post-processing: merge adjacent + drop unproductive ──────────────
436	
437	const MERGE_AZIMUTH_DEG = 20;
438	const MERGE_TILT_DEG = 8;
439	const MERGE_HULL_DIST_M = 1.5;
440	const DROP_NORTH_AZIMUTH_BAND = 30; // azimuth in [330, 30] = "true north" cone (narrower)
441	const DROP_NORTH_TILT_MIN = VARIANT_DROP_NORTH_TILT_MIN;
442	const DROP_WALLISH_TILT_MAX = 70;   // only drop near-vertical (was 60)
443	const DROP_TINY_AREA_MIN = VARIANT_DROP_TINY_AREA;
444	
445	function azimuthDelta(a: number, b: number): number {
446	  const d = Math.abs(a - b);
447	  return Math.min(d, 360 - d);
448	}
449	
450	function hullsClose(a: RoofFace, b: RoofFace, threshold: number): boolean {
451	  // Cheap: any vertex of A within `threshold` of any vertex of B.
452	  for (const va of a.vertices) {
453	    for (const vb of b.vertices) {
454	      const dx = va[0] - vb[0];
455	      const dz = va[2] - vb[2];
456	      if (Math.hypot(dx, dz) < threshold) return true;
457	    }
458	  }
459	  return false;
460	}
461	
462	function canMerge(a: RoofFace, b: RoofFace): boolean {
463	  if (azimuthDelta(a.azimuth, b.azimuth) > MERGE_AZIMUTH_DEG) return false;
464	  if (Math.abs(a.tilt - b.tilt) > MERGE_TILT_DEG) return false;
465	  return hullsClose(a, b, MERGE_HULL_DIST_M);
466	}
467	
468	function mergeTwoFaces(a: RoofFace, b: RoofFace, newId: number): RoofFace {
469	  const totalArea = a.area + b.area;
470	  // Area-weighted normal.
471	  const nx = (a.normal[0] * a.area + b.normal[0] * b.area) / totalArea;
472	  const ny = (a.normal[1] * a.area + b.normal[1] * b.area) / totalArea;
473	  const nz = (a.normal[2] * a.area + b.normal[2] * b.area) / totalArea;
474	  const len = Math.hypot(nx, ny, nz) || 1;
475	  const normal: [number, number, number] = [nx / len, ny / len, nz / len];
476	  const azimuth = Math.round(azimuthFromNormal(normal));
477	  const tilt = Math.round(tiltFromNormal(normal));
478	  const vertices = convexHullXZ([...a.vertices, ...b.vertices]);
479	  return {
480	    id: newId,
481	    normal,
482	    area: Math.round(totalArea * 10) / 10,
483	    usableArea: Math.round(totalArea * 10) / 10,
484	    azimuth,
485	    tilt,
486	    vertices,
487	    yieldKwhPerSqm: computeYield(azimuth, tilt),
488	  };
489	}
490	
491	function mergeFaces(faces: RoofFace[]): RoofFace[] {
492	  const merged = [...faces];
493	  let changed = true;
494	  let nextId = faces.length;
495	  while (changed) {
496	    changed = false;
497	    outer: for (let i = 0; i < merged.length; i++) {
498	      for (let j = i + 1; j < merged.length; j++) {
499	        if (canMerge(merged[i], merged[j])) {
500	          merged[i] = mergeTwoFaces(merged[i], merged[j], nextId++);
501	          merged.splice(j, 1);
502	          changed = true;
503	          break outer;
504	        }
505	      }
506	    }
507	  }
508	  // Re-id sequentially so face.id matches array index downstream.
509	  return merged.map((f, idx) => ({ ...f, id: idx }));
510	}
511	
512	// Yield threshold below which a face isn't worth panels.
513	const DROP_LOW_YIELD = VARIANT_DROP_LOW_YIELD;
514	
515	function dropBadFaces(faces: RoofFace[]): { kept: RoofFace[]; dropped: { face: RoofFace; reason: string }[] } {
516	  const kept: RoofFace[] = [];
517	  const dropped: { face: RoofFace; reason: string }[] = [];
518	  for (const f of faces) {
519	    if (f.area < DROP_TINY_AREA_MIN) {
520	      dropped.push({ face: f, reason: `area<${DROP_TINY_AREA_MIN}` });
521	      continue;
522	    }
523	    if (f.tilt > DROP_WALLISH_TILT_MAX) {
524	      dropped.push({ face: f, reason: `tilt>${DROP_WALLISH_TILT_MAX}` });
