227	function scoreVariant(data: AnalysisData): Pick<Scored, 'panelCount' | 'panelArea' | 'faceArea' | 'coverage' | 'score' | 'reason'> {
228	  const panelCount = data.modulePositions?.length ?? 0;
229	  const faceArea = data.faces.reduce((s, f) => s + f.area, 0);
230	  const panelArea = panelCount * PANEL_AREA;
231	  const coverage = faceArea > 0 ? panelArea / faceArea : 0;
232	
233	  // Hard penalties for unphysical outcomes.
234	  if (faceArea < 1) return { panelCount, panelArea, faceArea, coverage, score: 0, reason: 'no roof' };
235	  if (coverage > 0.95) return { panelCount, panelArea, faceArea, coverage, score: 0.05, reason: 'over-stacked (>95%)' };
236	  if (coverage < 0.10) return { panelCount, panelArea, faceArea, coverage, score: 0.10, reason: 'starved (<10%)' };
237	
238	  // Smooth peak at 40% coverage. Score is in (0, 1].
239	  const score = 1 / (1 + 5 * Math.abs(coverage - 0.40));
240	  const reason =
241	    coverage > 0.55 ? 'over-placement' : coverage < 0.25 ? 'under-placement' : 'on target';
242	  return { panelCount, panelArea, faceArea, coverage, score, reason };
243	}
