245	async function readVariantOutput(houseId: string, suffix: string): Promise<AnalysisData | null> {
246	  try {
247	    const raw = await fs.readFile(path.join(BAKED_DIR, `${houseId}-analysis${suffix}.json`), 'utf-8');
248	    return JSON.parse(raw) as AnalysisData;
249	  } catch {
250	    return null;
251	  }
252	}
