254	async function main() {
255	  const houseId = process.argv[2] ?? 'brandenburg';
256	
257	  console.log(`Running ${VARIANTS.length} variants for ${houseId}…`);
258	  for (const v of VARIANTS) console.log(`  ${v.suffix} (${v.name}): ${v.description}`);
259	  console.log('');
260	
261	  // Stage 1: seed the OSM polygon cache by running ONE variant. This avoids
262	  // 7 parallel Overpass requests racing — without the cache, Overpass rate-
263	  // limits some of them and the affected variants silently fall back to the
264	  // 15 m radius cylinder, which produces wildly inflated roofs.
265	  const t0 = Date.now();
266	  const cachePath = path.join(BAKED_DIR, `${houseId}-osm-polygon.json`);
267	  let cached = false;
268	  try { await fs.access(cachePath); cached = true; } catch { /* not cached */ }
269	  if (!cached) {
270	    console.log('Seeding OSM polygon cache (running variant -A first)…');
271	    await runChild(houseId, VARIANTS[0].env);
272	    console.log('Cache seeded. Running remaining variants in parallel…\n');
273	  } else {
274	    console.log('Using cached OSM polygon. Running all variants in parallel…\n');
275	  }
276	
277	  // Stage 2: run the rest (or all if cache was warm) in parallel.
278	  const toRun = cached ? VARIANTS : VARIANTS.slice(1);
279	  await Promise.allSettled(toRun.map((v) => runChild(houseId, v.env)));
280	  console.log(`\nAll variants done in ${((Date.now() - t0) / 1000).toFixed(1)}s\n`);
281	
282	  // Collect + score by reading each variant's output file. A missing file
283	  // means that variant crashed; we just skip it.
284	  const scored: Scored[] = [];
285	  for (const v of VARIANTS) {
286	    const data = await readVariantOutput(houseId, v.suffix);
287	    if (!data) {
288	      console.log(`  ${v.suffix} (${v.name}): no output file (variant failed)`);
289	      continue;
290	    }
291	    const s = scoreVariant(data);
292	    scored.push({ variant: v, data, ...s });
293	  }
294	
295	  if (scored.length === 0) {
296	    console.error('No variant produced output — aborting.');
297	    process.exit(1);
298	  }
299	
300	  scored.sort((a, b) => b.score - a.score);
301	
302	  console.log('\n=== Variant scores ===');
303	  console.log('  variant       roof    panels  panelArea  coverage  score  status');
304	  for (const s of scored) {
305	    console.log(
306	      `  ${s.variant.suffix} (${s.variant.name.padEnd(13)}) ` +
307	        `${s.faceArea.toFixed(0).padStart(5)} m²  ` +
308	        `${s.panelCount.toString().padStart(4)}    ` +
309	        `${s.panelArea.toFixed(1).padStart(6)} m²  ` +
310	        `${(s.coverage * 100).toFixed(0).padStart(4)}%    ` +
311	        `${s.score.toFixed(3)}  ` +
312	        `${s.reason}`,
313	    );
314	  }
315	
316	  // ---- Consensus voting on panel positions across variants ----
317	  //
318	  // Single-best-variant picking is brittle: D for Ritterstraße and F for
319	  // Address 4 give the right panel count but lose to the score function.
320	  // Consensus voting fixes this by trusting positions that MULTIPLE variants
321	  // independently agree on. A position kept by N≥3 variants is much more
322	  // likely to be a real panel slot than one only one variant ever proposes.
323	  const PROX_M = 0.7; // panels closer than this in XZ are "the same slot"
324	  // MIN_VOTES floor of 2 keeps slots even when only a couple of variants
325	  // independently propose them — important for Reihenhäuser where the eaves
326	  // are caught by only the buffer variants. The dynamic threshold below
327	  // ratchets it up when the resulting coverage is unphysically high.
328	  const MIN_VOTES = 2;
329	
330	  // Each cluster: array of {panel, variantSuffix}
331	  type Cluster = { x: number; y: number; z: number; voters: Set<string>; panels: ModulePos[] };
332	  const clusters: Cluster[] = [];
333	
334	  for (const s of scored) {
335	    const panels = s.data.modulePositions ?? [];
336	    for (const p of panels) {
337	      let assigned = false;
338	      for (const c of clusters) {
339	        if (Math.hypot(p.x - c.x, p.z - c.z) < PROX_M && Math.abs(p.y - c.y) < 1.5) {
340	          c.voters.add(s.variant.suffix);
341	          c.panels.push(p);
342	          // Update cluster centroid (running mean)
343	          const n = c.panels.length;
344	          c.x = (c.x * (n - 1) + p.x) / n;
345	          c.y = (c.y * (n - 1) + p.y) / n;
346	          c.z = (c.z * (n - 1) + p.z) / n;
347	          assigned = true;
348	          break;
349	        }
350	      }
351	      if (!assigned) {
352	        clusters.push({ x: p.x, y: p.y, z: p.z, voters: new Set([s.variant.suffix]), panels: [p] });
